{
  "name": "E-Minutasi: Manajemen Arsip Perkara",
  "description": "Aplikasi pelacakan status minutasi dan lokasi fisik berkas perkara pengadilan dengan fitur scan QR dan manajemen dokumen digital.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum CaseType {
  GUGATAN = 'Gugatan',
  PERMOHONAN = 'Permohonan'
}

export interface StorageLocation {
  roomNo: string;
  shelfNo: string;
  levelNo: string;
  boxNo: string;
}

export interface CaseData {
  id: string;
  caseNumber: string;
  caseType: CaseType;
  classification: string;
  parties: string;
  decisionDate: string;
  bhtDate?: string; // Optional, only for Gugatan
  isArchived: boolean;
  storage?: StorageLocation;
  pdfUrl?: string;
}

export interface SearchParams {
  caseNumber: string;
  caseType: CaseType;
  year: string;
}

import { CaseType, CaseData } from './types';

export const MOCK_CASES: CaseData[] = [
  {
    id: '1',
    caseNumber: '123/Pdt.G/2023/PA.Sbg',
    caseType: CaseType.GUGATAN,
    classification: 'Cerai Gugat',
    parties: 'Ahmad vs Siti',
    decisionDate: '2023-10-15',
    bhtDate: '2023-10-29',
    isArchived: true,
    storage: {
      roomNo: 'A1',
      shelfNo: 'L-05',
      levelNo: '3',
      boxNo: 'B-102'
    }
  },
  {
    id: '2',
    caseNumber: '45/Pdt.P/2024/PA.Sbg',
    caseType: CaseType.PERMOHONAN,
    classification: 'Dispensasi Kawin',
    parties: 'Budi Santoso',
    decisionDate: '2024-01-20',
    isArchived: false
  }
];

import { GoogleGenAI, Type } from "@google/genai";
import { CaseData, CaseType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateCaseDetails(caseNumber: string, type: CaseType): Promise<Partial<CaseData>> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate realistic Indonesian court case metadata for Case Number: ${caseNumber} and Type: ${type}. 
      Make it look professional. Return as JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classification: { type: Type.STRING, description: "Classification of the case" },
            parties: { type: Type.STRING, description: "Parties involved (e.g. A vs B or Single Name)" },
            decisionDate: { type: Type.STRING, description: "ISO date of decision" },
            bhtDate: { type: Type.STRING, description: "ISO date of final legal force, only if Gugatan" }
          },
          required: ["classification", "parties", "decisionDate"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini service error:", error);
    return {};
  }
}

import React, { useState } from 'react';
import { QrCode, X, Camera } from 'lucide-react';

interface ScannerProps {
  onScan: (result: string) => void;
  onClose: () => void;
}

const Scanner: React.FC<ScannerProps> = ({ onScan, onClose }) => {
  const [isScanning, setIsScanning] = useState(false);

  const simulateScan = () => {
    setIsScanning(true);
    // Simulate camera delay
    setTimeout(() => {
      onScan("123/Pdt.G/2023/PA.Sbg");
      setIsScanning(false);
      onClose();
    }, 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl w-full max-w-md overflow-hidden shadow-2xl">
        <div className="p-4 border-b flex justify-between items-center bg-slate-900 text-white">
          <h3 className="font-bold flex items-center gap-2">
            <QrCode className="w-5 h-5" />
            Scan QR Perkara
          </h3>
          <button onClick={onClose} className="p-1 hover:bg-white/20 rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="aspect-square bg-slate-100 flex flex-col items-center justify-center p-8 relative">
          <div className="w-64 h-64 border-2 border-dashed border-blue-500 rounded-xl flex items-center justify-center relative overflow-hidden">
            {isScanning ? (
              <div className="absolute inset-0 bg-blue-500/10 animate-pulse flex items-center justify-center">
                <div className="w-full h-1 bg-blue-500 absolute top-0 animate-[scan_2s_ease-in-out_infinite]"></div>
                <Camera className="w-12 h-12 text-blue-500 animate-bounce" />
              </div>
            ) : (
              <QrCode className="w-20 h-20 text-slate-300" />
            )}
          </div>

          <style>{`
            @keyframes scan {
              0% { transform: translateY(0); }
              50% { transform: translateY(256px); }
              100% { transform: translateY(0); }
            }
          `}</style>

          <p className="mt-6 text-sm text-slate-500 text-center">
            Posisikan QR Code perkara di dalam kotak untuk memindai otomatis.
          </p>

          {!isScanning && (
            <button 
              onClick={simulateScan}
              className="mt-6 px-6 py-2 bg-blue-600 text-white rounded-full font-semibold shadow-lg shadow-blue-200 hover:bg-blue-700 active:scale-95 transition-all"
            >
              Mulai Memindai
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default Scanner;

