import React, { useState } from 'react';
import { CaseData, StorageLocation } from '../types';
import { Box, MapPin, Layers, Archive, FileUp, FileText, ChevronDown, ChevronUp } from 'lucide-react';

interface MinutasiSectionProps {
  caseData: CaseData;
  onUpdate: (updatedCase: CaseData) => void;
}

const MinutasiSection: React.FC<MinutasiSectionProps> = ({ caseData, onUpdate }) => {
  const [showLocationForm, setShowLocationForm] = useState(caseData.isArchived);
  const [formData, setFormData] = useState<StorageLocation>(
    caseData.storage || { roomNo: '', shelfNo: '', levelNo: '', boxNo: '' }
  );

  const toggleStatus = () => {
    const nextArchived = !caseData.isArchived;
    onUpdate({
      ...caseData,
      isArchived: nextArchived,
      storage: nextArchived ? formData : undefined
    });
    setShowLocationForm(nextArchived);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    const newStorage = { ...formData, [name]: value };
    setFormData(newStorage);
    if (caseData.isArchived) {
      onUpdate({ ...caseData, storage: newStorage });
    }
  };

  return (
    <div className="mt-8 space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
          <Archive className="w-6 h-6 text-blue-600" />
          Status Minutasi & Lokasi Arsip
        </h3>
        <button
          onClick={toggleStatus}
          className={`px-6 py-2 rounded-full font-bold transition-all shadow-md flex items-center gap-2 ${
            caseData.isArchived 
              ? 'bg-slate-200 text-slate-700 hover:bg-slate-300' 
              : 'bg-green-600 text-white hover:bg-green-700 shadow-green-100'
          }`}
        >
          {caseData.isArchived ? 'Batalkan Minutasi' : 'Tandai Sudah Minutasi'}
        </button>
      </div>

      {showLocationForm && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2">
              <MapPin className="w-4 h-4" />
              Informasi Lokasi Fisik
            </h4>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <InputField 
                label="No. Ruang" 
                name="roomNo" 
                value={formData.roomNo} 
                onChange={handleInputChange} 
                placeholder="Ex: R-01"
              />
              <InputField 
                label="No. Lemari/Rak" 
                name="shelfNo" 
                value={formData.shelfNo} 
                onChange={handleInputChange} 
                placeholder="Ex: L-10"
              />
              <InputField 
                label="No. Tingkat" 
                name="levelNo" 
                value={formData.levelNo} 
                onChange={handleInputChange} 
                placeholder="Ex: 5"
              />
              <InputField 
                label="No. Box" 
                name="boxNo" 
                value={formData.boxNo} 
                onChange={handleInputChange} 
                placeholder="Ex: B-22"
              />
            </div>
          </div>

          <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-lg flex flex-col justify-between">
            <div>
              <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">E-Document</h4>
              <p className="text-slate-300 text-sm mb-6 italic">Unggah berkas PDF minutasi atau lihat dokumen yang sudah tersimpan di server.</p>
            </div>

            <div className="flex flex-col gap-3">
              <button className="flex items-center justify-center gap-2 bg-white text-slate-900 py-3 rounded-xl font-bold hover:bg-slate-100 transition-colors">
                <FileText className="w-5 h-5" />
                Lihat PDF
              </button>
              <button className="flex items-center justify-center gap-2 border border-white/20 text-white py-3 rounded-xl font-bold hover:bg-white/10 transition-colors">
                <FileUp className="w-5 h-5" />
                Upload / Scan
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const InputField = ({ label, name, value, onChange, placeholder }: any) => (
  <div className="space-y-1.5">
    <label className="text-[11px] font-bold text-slate-500 uppercase">{label}</label>
    <input
      type="text"
      name={name}
      value={value}
      onChange={onChange}
      placeholder={placeholder}
      className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
    />
  </div>
);

export default MinutasiSection;

import React, { useState } from 'react';
import { HashRouter as Router } from 'react-router-dom';
import { Search, QrCode, FileSearch, Scale, AlertCircle, Loader2 } from 'lucide-react';
import { CaseData, CaseType, SearchParams } from './types';
import { MOCK_CASES } from './constants';
import CaseDetails from './components/CaseDetails';
import MinutasiSection from './components/MinutasiSection';
import Scanner from './components/Scanner';
import { generateCaseDetails } from './services/geminiService';

const App: React.FC = () => {
  const [params, setParams] = useState<SearchParams>({
    caseNumber: '',
    caseType: CaseType.GUGATAN,
    year: new Date().getFullYear().toString()
  });

  const [activeCase, setActiveCase] = useState<CaseData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showScanner, setShowScanner] = useState(false);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!params.caseNumber) return;

    setLoading(true);
    setError(null);

    try {
      // 1. Check mock data first
      const fullCaseNum = `${params.caseNumber}/${params.caseType === CaseType.GUGATAN ? 'Pdt.G' : 'Pdt.P'}/${params.year}/PA.Sbg`;
      const found = MOCK_CASES.find(c => c.caseNumber === fullCaseNum || c.caseNumber === params.caseNumber);

      if (found) {
        setActiveCase(found);
      } else {
        // 2. Use Gemini to simulate a lookup if not in mock
        const details = await generateCaseDetails(params.caseNumber, params.caseType);
        setActiveCase({
          id: Math.random().toString(36).substr(2, 9),
          caseNumber: fullCaseNum,
          caseType: params.caseType,
          classification: details.classification || 'Klasifikasi Tidak Diketahui',
          parties: details.parties || 'Pihak Tidak Terdata',
          decisionDate: details.decisionDate || new Date().toISOString().split('T')[0],
          bhtDate: details.bhtDate,
          isArchived: false
        });
      }
    } catch (err) {
      setError("Gagal mengambil data perkara. Pastikan nomor perkara benar.");
    } finally {
      setLoading(false);
    }
  };

  const handleScanSuccess = (result: string) => {
    setParams(prev => ({ ...prev, caseNumber: result }));
    // Automatically trigger search
    setTimeout(() => handleSearch(), 100);
  };

  const updateCase = (updated: CaseData) => {
    setActiveCase(updated);
  };

  return (
    <Router>
      <div className="min-h-screen pb-20">
        {/* Header */}
        <header className="bg-slate-900 text-white py-6 shadow-xl sticky top-0 z-40">
          <div className="max-w-5xl mx-auto px-4 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-2 rounded-xl">
                <Scale className="w-8 h-8" />
              </div>
              <div>
                <h1 className="text-xl font-bold leading-tight">E-Minutasi</h1>
                <p className="text-slate-400 text-xs uppercase tracking-widest font-bold">Pengadilan Agama Subang</p>
              </div>
            </div>
          </div>
        </header>

        <main className="max-w-5xl mx-auto px-4 pt-8">
          {/* Search Card */}
          <section className="bg-white rounded-2xl shadow-lg border border-slate-200 overflow-hidden mb-8">
            <div className="p-1 bg-gradient-to-r from-blue-600 to-indigo-600"></div>
            <div className="p-8">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Cari Berkas Perkara</h2>
                  <p className="text-slate-500 text-sm">Gunakan QR Code atau masukkan nomor perkara secara manual.</p>
                </div>
                <button 
                  onClick={() => setShowScanner(true)}
                  className="flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-xl font-bold hover:bg-slate-800 transition-all active:scale-95 shadow-lg shadow-slate-200"
                >
                  <QrCode className="w-5 h-5" />
                  Scan QR Perkara
                </button>
              </div>

              <form onSubmit={handleSearch} className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="md:col-span-2">
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Nomor Perkara</label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                    <input 
                      type="text" 
                      placeholder="Contoh: 123"
                      value={params.caseNumber}
                      onChange={e => setParams({...params, caseNumber: e.target.value})}
                      className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-800 font-medium"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Jenis</label>
                  <select 
                    value={params.caseType}
                    onChange={e => setParams({...params, caseType: e.target.value as CaseType})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-800 font-medium appearance-none"
                  >
                    <option value={CaseType.GUGATAN}>Gugatan</option>
                    <option value={CaseType.PERMOHONAN}>Permohonan</option>
                  </select>
                </div>

                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Tahun</label>
                  <input 
                    type="number" 
                    value={params.year}
                    onChange={e => setParams({...params, year: e.target.value})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-800 font-medium"
                  />
                </div>

                <div className="md:col-span-4 mt-2">
                  <button 
                    type="submit"
                    disabled={loading || !params.caseNumber}
                    className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold hover:bg-blue-700 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2 shadow-xl shadow-blue-100"
                  >
                    {loading ? (
                      <><Loader2 className="w-5 h-5 animate-spin" /> Sedang Mencari...</>
                    ) : (
                      <><FileSearch className="w-5 h-5" /> Cari Data Perkara</>
                    )}
                  </button>
                </div>
              </form>
            </div>
          </section>

          {/* Error Message */}
          {error && (
            <div className="bg-red-50 border border-red-200 p-4 rounded-xl flex items-start gap-3 text-red-700 mb-8 animate-in fade-in slide-in-from-top-2">
              <AlertCircle className="w-5 h-5 mt-0.5 shrink-0" />
              <p className="font-medium">{error}</p>
            </div>
          )}

          {/* Results Area */}
          {activeCase ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <CaseDetails data={activeCase} />
              <MinutasiSection caseData={activeCase} onUpdate={updateCase} />
            </div>
          ) : !loading && (
            <div className="text-center py-20 px-4 bg-slate-100/50 rounded-3xl border-2 border-dashed border-slate-200">
              <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
                <Search className="w-10 h-10 text-slate-300" />
              </div>
              <h3 className="text-lg font-bold text-slate-800 mb-2">Belum ada data yang ditampilkan</h3>
              <p className="text-slate-500 max-w-sm mx-auto">Silakan masukkan nomor perkara atau gunakan scanner untuk mulai mengelola minutasi berkas.</p>
            </div>
          )}
        </main>

        {/* Floating Scanner Overlay */}
        {showScanner && (
          <Scanner onScan={handleScanSuccess} onClose={() => setShowScanner(false)} />
        )}

        {/* Footer info */}
        <footer className="mt-12 py-12 border-t border-slate-200 bg-white">
          <div className="max-w-5xl mx-auto px-4 text-center">
            <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Sistem Manajemen Arsip Digital &copy; 2024</p>
            <p className="text-slate-500 text-sm mt-2 font-medium">Pengadilan Agama Subang Kelas I.A</p>
          </div>
        </footer>
      </div>
    </Router>
  );
};

export default App;

