            <div className="flex-1 bg-slate-200 overflow-auto p-4 flex justify-center items-start">
              {caseData.pdfUrl.startsWith('data:application/pdf') ? (
                <iframe 
                  src={caseData.pdfUrl} 
                  className="w-full h-full rounded shadow-xl"
                  title="PDF Viewer"
                />
              ) : (
                <img 
                  src={caseData.pdfUrl} 
                  alt="Scanned Document" 
                  className="max-w-full shadow-2xl rounded"
                />
              )}
            </div>
            <div className="p-4 bg-slate-50 border-t flex justify-end">
              <button 
                onClick={() => setShowViewer(false)}
                className="px-6 py-2 bg-slate-900 text-white rounded-lg font-bold hover:bg-slate-800 transition-colors"
              >
                Tutup Viewer
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const InputField = ({ label, name, value, onChange, placeholder }: any) => (
