import React, { useState, useRef } from 'react';
import { CaseData, StorageLocation } from '../types';
import { Box, MapPin, Layers, Archive, FileUp, FileText, ChevronDown, ChevronUp, X, Eye, FileCheck, Save, Loader2, Check } from 'lucide-react';

interface MinutasiSectionProps {
  caseData: CaseData;
  onUpdate: (updatedCase: CaseData) => void;
}

const MinutasiSection: React.FC<MinutasiSectionProps> = ({ caseData, onUpdate }) => {
  const [showLocationForm, setShowLocationForm] = useState(caseData.isArchived);
  const [showViewer, setShowViewer] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);

  const [formData, setFormData] = useState<StorageLocation>(
    caseData.storage || { roomNo: '', shelfNo: '', levelNo: '', boxNo: '' }
  );
  const [tempPdfUrl, setTempPdfUrl] = useState<string | undefined>(caseData.pdfUrl);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const toggleStatus = () => {
    const nextArchived = !caseData.isArchived;
    // We update immediately for the status toggle as it changes the UI layout
    onUpdate({
      ...caseData,
      isArchived: nextArchived,
      storage: nextArchived ? formData : undefined
    });
    setShowLocationForm(nextArchived);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    setSaveSuccess(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setTempPdfUrl(reader.result as string);
        setSaveSuccess(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = async () => {
    setIsSaving(true);
    setSaveSuccess(false);

    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1200));

    onUpdate({
      ...caseData,
      storage: formData,
      pdfUrl: tempPdfUrl
    });

    setIsSaving(false);
    setSaveSuccess(true);

    // Reset success state after 3 seconds
    setTimeout(() => setSaveSuccess(false), 3000);
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="mt-8 space-y-6">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
          <Archive className="w-6 h-6 text-blue-600" />
          Status Minutasi & Lokasi Arsip
        </h3>
        <button
          onClick={toggleStatus}
          className={`w-full sm:w-auto px-6 py-2 rounded-full font-bold transition-all shadow-md flex items-center justify-center gap-2 ${
            caseData.isArchived 
              ? 'bg-slate-200 text-slate-700 hover:bg-slate-300' 
              : 'bg-green-600 text-white hover:bg-green-700 shadow-green-100'
          }`}
        >
          {caseData.isArchived ? 'Batalkan Minutasi' : 'Tandai Sudah Minutasi'}
        </button>
      </div>

      {showLocationForm && (
        <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2">
                <MapPin className="w-4 h-4" />
                Informasi Lokasi Fisik
              </h4>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <InputField 
                  label="No. Ruang" 
                  name="roomNo" 
                  value={formData.roomNo} 
                  onChange={handleInputChange} 
                  placeholder="Ex: R-01"
                />
                <InputField 
                  label="No. Lemari/Rak" 
                  name="shelfNo" 
                  value={formData.shelfNo} 
                  onChange={handleInputChange} 
                  placeholder="Ex: L-10"
                />
                <InputField 
                  label="No. Tingkat" 
                  name="levelNo" 
                  value={formData.levelNo} 
                  onChange={handleInputChange} 
                  placeholder="Ex: 5"
                />
                <InputField 
                  label="No. Box" 
                  name="boxNo" 
                  value={formData.boxNo} 
                  onChange={handleInputChange} 
                  placeholder="Ex: B-22"
                />
              </div>
            </div>

            <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-lg flex flex-col justify-between overflow-hidden relative">
              {tempPdfUrl && (
                <div className="absolute top-2 right-2 bg-emerald-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full flex items-center gap-1 shadow-lg">
                  <FileCheck className="w-3 h-3" /> {tempPdfUrl === caseData.pdfUrl ? 'VERIFIED' : 'PENDING SAVE'}
                </div>
              )}
              <div>
                <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">E-Document</h4>
                <p className="text-slate-300 text-sm mb-6 italic">
                  {tempPdfUrl 
                    ? 'Dokumen minutasi telah dipilih. Pastikan klik Simpan untuk memperbarui database.' 
                    : 'Unggah berkas PDF minutasi atau foto berkas yang sudah dijilid.'}
                </p>
              </div>

              <div className="flex flex-col gap-3">
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="application/pdf,image/*" 
                  onChange={handleFileUpload}
                />
                <button 
                  onClick={() => tempPdfUrl ? setShowViewer(true) : alert('Belum ada berkas diunggah')}
                  disabled={!tempPdfUrl}
                  className={`flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-colors ${
                    tempPdfUrl 
                      ? 'bg-white text-slate-900 hover:bg-slate-100 cursor-pointer' 
                      : 'bg-white/10 text-white/30 cursor-not-allowed'
                  }`}
                >
                  <Eye className="w-5 h-5" />
                  Lihat Berkas
                </button>
                <button 
                  onClick={triggerUpload}
                  className="flex items-center justify-center gap-2 border border-white/20 text-white py-3 rounded-xl font-bold hover:bg-white/10 transition-colors"
                >
                  <FileUp className="w-5 h-5" />
                  {tempPdfUrl ? 'Ganti Berkas' : 'Upload / Scan'}
                </button>
              </div>
            </div>
          </div>

          {/* Action Footer: Save Button */}
          <div className="flex justify-end pt-2">
            <button
              onClick={handleSave}
              disabled={isSaving}
              className={`flex items-center gap-2 px-8 py-4 rounded-xl font-bold transition-all shadow-xl active:scale-95 ${
                saveSuccess 
                  ? 'bg-emerald-500 text-white shadow-emerald-200' 
                  : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'
              }`}
            >
              {isSaving ? (
                <><Loader2 className="w-5 h-5 animate-spin" /> Menyimpan...</>
              ) : saveSuccess ? (
                <><Check className="w-5 h-5" /> Berhasil Disimpan</>
              ) : (
                <><Save className="w-5 h-5" /> Simpan Data Minutasi</>
              )}
            </button>
          </div>
        </div>
      )}

      {/* Document Viewer Modal */}
      {showViewer && tempPdfUrl && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/90 p-4 sm:p-8 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-4xl h-full max-h-[90vh] rounded-2xl overflow-hidden flex flex-col relative">
            <div className="p-4 border-b flex justify-between items-center bg-slate-900 text-white">
              <h3 className="font-bold flex items-center gap-2 truncate pr-4">
                <FileText className="w-5 h-5" />
                Preview Berkas: {caseData.caseNumber}
