interface AddCaseFormProps {
  onSave: (newCase: CaseData) => void;
  onCancel: () => void;
  initialData?: CaseData | null;
}

const AddCaseForm: React.FC<AddCaseFormProps> = ({ onSave, onCancel, initialData }) => {
  const [formData, setFormData] = useState<Partial<CaseData>>(
    initialData || {
      caseType: CaseType.GUGATAN,
      year: new Date().getFullYear().toString(),
      decisionDate: new Date().toISOString().split('T')[0],
      isArchived: false
