                    <td colSpan={6} className="py-12 text-center text-slate-400 italic text-sm">
                      Tidak ada data perkara ditemukan.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

