            <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Sistem Manajemen Arsip Digital &copy; 2024</p>
            <p className="text-slate-500 text-sm mt-2 font-medium">Pengadilan Agama Prabumulih Kelas II</p>
