import React, { useState } from 'react';
import { CaseData, CaseType } from '../types';
import { FileText, ChevronRight, Archive, Clock, Search, MapPin, FileCheck, FileWarning, Calendar, Info, Trash2, RotateCcw } from 'lucide-react';

interface CaseListProps {
  cases: CaseData[];
  onSelectCase: (caseData: CaseData) => void;
  onDeleteCase: (id: string) => void;
  onUpdateCase: (updatedCase: CaseData) => void;
}

const CaseList: React.FC<CaseListProps> = ({ cases, onSelectCase, onDeleteCase, onUpdateCase }) => {
  const [activeTab, setActiveTab] = useState<CaseType>(CaseType.GUGATAN);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredCases = cases.filter(c => 
    c.caseType === activeTab && 
    (c.caseNumber.toLowerCase().includes(searchTerm.toLowerCase()) || 
     c.parties.toLowerCase().includes(searchTerm.toLowerCase()) ||
     c.classification.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const stats = {
    gugatan: cases.filter(c => c.caseType === CaseType.GUGATAN).length,
    permohonan: cases.filter(c => c.caseType === CaseType.PERMOHONAN).length
  };

  const isGugatan = activeTab === CaseType.GUGATAN;

  const handleDeleteCase = (id: string, caseNumber: string) => {
    if (window.confirm(`Hapus PERKARA nomor ${caseNumber} secara permanen? Data registrasi dan minutasi akan hilang.`)) {
      onDeleteCase(id);
    }
  };

  const handleResetMinutasi = (caseData: CaseData) => {
    if (window.confirm(`Hapus STATUS MINUTASI untuk perkara ${caseData.caseNumber}? Data lokasi arsip dan dokumen digital akan dibersihkan, status kembali ke 'Proses'.`)) {
      onUpdateCase({
        ...caseData,
        isArchived: false,
        storage: undefined,
        pdfUrl: undefined
      });
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-1 bg-gradient-to-r from-slate-700 to-slate-900"></div>
        <div className="p-6 md:p-8">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
            <div>
              <h2 className="text-xl font-bold text-slate-800">Daftar Berkas Terinput</h2>
              <p className="text-slate-500 text-sm">Manajemen registrasi dan monitoring status minutasi perkara.</p>
            </div>

            <div className="relative w-full md:w-72">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
              <input 
                type="text"
                placeholder="Cari berkas..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm"
              />
            </div>
          </div>

          {/* Tabs */}
          <div className="flex p-1 bg-slate-100 rounded-xl mb-6 w-fit">
            <button 
              onClick={() => setActiveTab(CaseType.GUGATAN)}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${
                activeTab === CaseType.GUGATAN 
                  ? 'bg-white text-blue-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Gugatan
              <span className={`px-2 py-0.5 rounded-full text-[10px] ${activeTab === CaseType.GUGATAN ? 'bg-blue-100 text-blue-600' : 'bg-slate-200 text-slate-500'}`}>
                {stats.gugatan}
              </span>
            </button>
            <button 
              onClick={() => setActiveTab(CaseType.PERMOHONAN)}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${
                activeTab === CaseType.PERMOHONAN 
                  ? 'bg-white text-emerald-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Permohonan
              <span className={`px-2 py-0.5 rounded-full text-[10px] ${activeTab === CaseType.PERMOHONAN ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                {stats.permohonan}
              </span>
            </button>
          </div>

          {/* Table */}
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse min-w-[1000px]">
              <thead>
                <tr className="border-b border-slate-100">
                  <th className="py-4 px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">No. Perkara</th>
                  <th className="py-4 px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Klasifikasi</th>
                  <th className="py-4 px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Para Pihak</th>
                  <th className="py-4 px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Tgl Putus</th>
                  {isGugatan && <th className="py-4 px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Tgl BHT</th>}
                  <th className="py-4 px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Status Minutasi</th>
                  <th className="py-4 px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-right">Aksi</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredCases.length > 0 ? (
                  filteredCases.map((c) => (
                    <tr key={c.id} className="group hover:bg-slate-50 transition-colors">
                      <td className="py-5 px-4">
                        <div className="font-bold text-slate-800 text-sm leading-none">{c.caseNumber}</div>
                        {c.isArchived && c.storage && (
                          <div className="flex gap-1 mt-2">
                            <span className="text-[9px] bg-blue-50 text-blue-600 px-1 rounded border border-blue-100 font-bold" title="Lokasi Arsip">
                              {c.storage.roomNo}/{c.storage.shelfNo}
                            </span>
                          </div>
                        )}
                      </td>
                      <td className="py-5 px-4">
                        <span className="text-sm font-semibold text-slate-700">{c.classification}</span>
                      </td>
                      <td className="py-5 px-4">
                        <div className="text-[11px] text-slate-500 font-medium leading-tight max-w-[200px]">
                          {c.parties}
                        </div>
                      </td>
                      <td className="py-5 px-4 text-center">
                        <div className="inline-flex items-center gap-1.5 px-2 py-1 bg-slate-50 rounded-lg border border-slate-100 text-[11px] font-bold text-slate-600">
                          <Calendar className="w-3 h-3 text-slate-400" />
                          {new Date(c.decisionDate).toLocaleDateString('id-ID', { day: '2-digit', month: '2-digit', year: 'numeric' })}
                        </div>
                      </td>
                      {isGugatan && (
                        <td className="py-5 px-4 text-center">
                          {c.bhtDate ? (
                            <div className="inline-flex items-center gap-1.5 px-2 py-1 bg-blue-50 rounded-lg border border-blue-100 text-[11px] font-bold text-blue-600">
                              <Info className="w-3 h-3 text-blue-400" />
                              {new Date(c.bhtDate).toLocaleDateString('id-ID', { day: '2-digit', month: '2-digit', year: 'numeric' })}
                            </div>
                          ) : (
                            <span className="text-[10px] text-slate-400 italic">Belum BHT</span>
                          )}
                        </td>
                      )}
                      <td className="py-5 px-4 text-center">
                        <div className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tighter ${
                          c.isArchived 
                            ? 'bg-green-100 text-green-700 border border-green-200' 
                            : 'bg-slate-100 text-slate-500 border border-slate-200'
                        }`}>
                          {c.isArchived ? <Archive className="w-3 h-3" /> : <Clock className="w-3 h-3" />}
                          {c.isArchived ? 'Selesai' : 'Proses'}
                        </div>
                        {c.pdfUrl && (
                          <div className="flex justify-center mt-1" title="E-Doc Tersedia">
                            <FileCheck className="w-3.5 h-3.5 text-emerald-500" />
                          </div>
                        )}
                      </td>
                      <td className="py-5 px-4 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <button 
                            onClick={() => onSelectCase(c)}
                            className="inline-flex items-center justify-center w-8 h-8 bg-slate-100 text-slate-600 rounded-lg hover:bg-blue-600 hover:text-white transition-all group-hover:shadow-md"
                            title="Edit / Detail"
                          >
                            <ChevronRight className="w-5 h-5" />
                          </button>

                          {/* Tombol Hapus Status Minutasi (Hanya muncul jika sudah Selesai) */}
                          {c.isArchived && (
                            <button 
                              onClick={() => handleResetMinutasi(c)}
                              className="inline-flex items-center justify-center w-8 h-8 bg-slate-100 text-blue-500 rounded-lg hover:bg-blue-100 transition-all group-hover:shadow-md border border-transparent hover:border-blue-200"
                              title="Hapus Status Minutasi (Reset ke Proses)"
                            >
                              <RotateCcw className="w-4 h-4" />
                            </button>
                          )}

                          <button 
                            onClick={() => handleDeleteCase(c.id, c.caseNumber)}
                            className="inline-flex items-center justify-center w-8 h-8 bg-slate-100 text-red-400 rounded-lg hover:bg-red-600 hover:text-white transition-all group-hover:shadow-md"
                            title="Hapus Perkara Permanen"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={isGugatan ? 7 : 6} className="py-12 text-center text-slate-400 italic text-sm">
                      Data tidak ditemukan dalam database lokal.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CaseList;

import React, { useState, useEffect } from 'react';
import { HashRouter as Router } from 'react-router-dom';
import { Search, QrCode, FileSearch, Scale, AlertCircle, Loader2, PlusCircle, LayoutDashboard, ListFilter } from 'lucide-react';
import { CaseData, CaseType, SearchParams } from './types';
import { MOCK_CASES } from './constants';
import CaseDetails from './components/CaseDetails';
import Scanner from './components/Scanner';
import AddCaseForm from './components/AddCaseForm';
import CaseList from './components/CaseList';
import { generateCaseDetails } from './services/geminiService';

const App: React.FC = () => {
  const [cases, setCases] = useState<CaseData[]>(MOCK_CASES);
  const [view, setView] = useState<'search' | 'add' | 'list'>('search');
  const [params, setParams] = useState<SearchParams>({
    caseNumber: '',
    caseType: CaseType.GUGATAN,
    year: new Date().getFullYear().toString()
  });

  const [activeCase, setActiveCase] = useState<CaseData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showScanner, setShowScanner] = useState(false);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!params.caseNumber) return;

    setLoading(true);
    setError(null);
    setView('search');

    try {
      const formattedCaseNum = params.caseNumber.includes('/') 
        ? params.caseNumber 
        : `${params.caseNumber}/${params.caseType === CaseType.GUGATAN ? 'Pdt.G' : 'Pdt.P'}/${params.year}/PA.Pbm`;

      const found = cases.find(c => c.caseNumber.toLowerCase() === formattedCaseNum.toLowerCase());

      if (found) {
        setActiveCase(found);
      } else {
        const details = await generateCaseDetails(params.caseNumber, params.caseType);
        const newAIResult: CaseData = {
          id: Math.random().toString(36).substr(2, 9),
          caseNumber: formattedCaseNum,
          caseType: params.caseType,
          classification: details.classification || 'Klasifikasi Tidak Diketahui',
          parties: details.parties || 'Pihak Tidak Terdata',
          decisionDate: details.decisionDate || new Date().toISOString().split('T')[0],
          bhtDate: details.bhtDate,
          isArchived: false
        };
        setActiveCase(newAIResult);
        setCases(prev => [...prev, newAIResult]);
      }
    } catch (err) {
      setError("Gagal mengambil data perkara. Pastikan nomor perkara benar.");
    } finally {
      setLoading(false);
    }
  };

  const handleInputPerkaraClick = () => {
    setActiveCase(null);
    setView('add');
  };

  const handleSaveOrUpdateCase = (finalCase: CaseData) => {
    const exists = cases.find(c => c.id === finalCase.id);
    if (exists) {
      setCases(prev => prev.map(c => c.id === finalCase.id ? finalCase : c));
    } else {
      setCases(prev => [...prev, finalCase]);
    }

    // If the case being updated is the active one, refresh it
    if (activeCase?.id === finalCase.id) {
      setActiveCase(finalCase);
    }
  };

  const handleDeleteCase = (id: string) => {
    setCases(prev => prev.filter(c => c.id !== id));
    if (activeCase?.id === id) {
      setActiveCase(null);
    }
    setView('list');
  };

  const handleScanSuccess = (result: string) => {
    setParams(prev => ({ ...prev, caseNumber: result }));
    setTimeout(() => handleSearch(), 100);
  };

  const selectCaseForEdit = (caseData: CaseData) => {
    setActiveCase(caseData);
    setView('add');
  };

  return (
    <Router>
      <div className="min-h-screen pb-20 bg-slate-50">
        {/* Header */}
        <header className="bg-slate-900 text-white py-4 shadow-xl sticky top-0 z-40">
          <div className="max-w-5xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-2 rounded-xl">
                <Scale className="w-8 h-8" />
              </div>
              <div onClick={() => {setView('search'); setActiveCase(null);}} className="cursor-pointer">
                <h1 className="text-xl font-bold leading-tight">E-Minutasi</h1>
                <p className="text-slate-400 text-[10px] uppercase tracking-widest font-bold">PA PRABUMULIH KELAS II</p>
              </div>
            </div>

            <nav className="flex bg-slate-800 p-1 rounded-xl overflow-x-auto no-scrollbar">
              <button 
                onClick={() => {setView('search'); setActiveCase(null);}}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all whitespace-nowrap ${
                  view === 'search' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'
                }`}
              >
                <LayoutDashboard className="w-4 h-4" />
                Dashboard
              </button>
              <button 
                onClick={() => setView('list')}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all whitespace-nowrap ${
                  view === 'list' ? 'bg-slate-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'
                }`}
              >
                <ListFilter className="w-4 h-4" />
                Berkas Terinput
              </button>
              <button 
                onClick={handleInputPerkaraClick}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all whitespace-nowrap ${
                  view === 'add' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'
                }`}
              >
                <PlusCircle className="w-4 h-4" />
                Input Perkara
              </button>
            </nav>
          </div>
        </header>

        <main className="max-w-5xl mx-auto px-4 pt-8">
          {view === 'add' ? (
            <AddCaseForm 
              initialData={activeCase}
              onSave={(c) => { handleSaveOrUpdateCase(c); setView('list'); setActiveCase(null); }} 
              onDelete={handleDeleteCase}
              onCancel={() => {setView('list'); setActiveCase(null);}} 
            />
          ) : view === 'list' ? (
            <CaseList 
              cases={cases} 
              onSelectCase={selectCaseForEdit}
              onDeleteCase={handleDeleteCase}
              onUpdateCase={handleSaveOrUpdateCase}
            />
          ) : (
            <>
              {/* Search Card */}
              <section className="bg-white rounded-2xl shadow-lg border border-slate-200 overflow-hidden mb-8 transition-all hover:shadow-xl">
                <div className="p-1 bg-gradient-to-r from-blue-600 to-indigo-600"></div>
                <div className="p-8">
                  <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
                    <div>
                      <h2 className="text-xl font-bold text-slate-800">Cari Berkas Perkara</h2>
                      <p className="text-slate-500 text-sm">Gunakan QR Code atau masukkan nomor perkara secara manual.</p>
                    </div>
                    <button 
                      onClick={() => setShowScanner(true)}
                      className="flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-xl font-bold hover:bg-slate-800 transition-all active:scale-95 shadow-lg shadow-slate-200"
                    >
                      <QrCode className="w-5 h-5" />
                      Scan QR Perkara
                    </button>
                  </div>

                  <form onSubmit={handleSearch} className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div className="md:col-span-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Nomor Perkara</label>
                      <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
                        <input 
                          type="text" 
                          placeholder="Contoh: 123"
                          value={params.caseNumber}
                          onChange={e => setParams({...params, caseNumber: e.target.value})}
                          className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-800 font-medium"
                        />
                      </div>
                    </div>

                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Jenis</label>
                      <select 
                        value={params.caseType}
                        onChange={e => setParams({...params, caseType: e.target.value as CaseType})}
                        className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-800 font-medium appearance-none"
                      >
                        <option value={CaseType.GUGATAN}>Gugatan</option>
                        <option value={CaseType.PERMOHONAN}>Permohonan</option>
                      </select>
                    </div>

                    <div>
                      <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Tahun</label>
                      <input 
                        type="number" 
                        value={params.year}
                        onChange={e => setParams({...params, year: e.target.value})}
                        className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-slate-800 font-medium"
                      />
                    </div>

                    <div className="md:col-span-4 mt-2">
                      <button 
                        type="submit"
                        disabled={loading || !params.caseNumber}
                        className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold hover:bg-blue-700 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-2 shadow-xl shadow-blue-100"
                      >
                        {loading ? (
                          <><Loader2 className="w-5 h-5 animate-spin" /> Sedang Mencari...</>
                        ) : (
                          <><FileSearch className="w-5 h-5" /> Cari Data Perkara</>
                        )}
                      </button>
                    </div>
                  </form>
                </div>
              </section>

              {/* Error Message */}
              {error && (
                <div className="bg-red-50 border border-red-200 p-4 rounded-xl flex items-start gap-3 text-red-700 mb-8 animate-in fade-in slide-in-from-top-2">
                  <AlertCircle className="w-5 h-5 mt-0.5 shrink-0" />
                  <p className="font-medium">{error}</p>
                </div>
              )}

              {/* Results Area */}
              {activeCase ? (
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                  <CaseDetails data={activeCase} />
                </div>
              ) : !loading && (
                <div className="text-center py-20 px-4 bg-white rounded-3xl border border-slate-200 shadow-sm">
                  <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
                    <Search className="w-10 h-10 text-slate-300" />
                  </div>
                  <h3 className="text-lg font-bold text-slate-800 mb-2">Belum ada data yang ditampilkan</h3>
                  <p className="text-slate-500 max-w-sm mx-auto">Silakan masukkan nomor perkara atau cari melalui menu Berkas Terinput.</p>
                </div>
              )}
            </>
          )}
        </main>

        {/* Overlays */}
        {showScanner && (
          <Scanner onScan={handleScanSuccess} onClose={() => setShowScanner(false)} />
        )}

        {/* Footer info */}
        <footer className="mt-12 py-12 border-t border-slate-200 bg-white">
          <div className="max-w-5xl mx-auto px-4 text-center">
            <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Sistem Manajemen Arsip Digital &copy; 2024</p>
            <p className="text-slate-500 text-sm mt-2 font-medium">Pengadilan Agama Prabumulih Kelas II</p>
          </div>
        </footer>
      </div>
    </Router>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { CaseData, CaseType, StorageLocation } from '../types';
import { Save, X, FilePlus2, Calendar, User, FileText, Archive, MapPin, FileUp, Eye, Loader2, Check, Trash2, RotateCcw } from 'lucide-react';

interface AddCaseFormProps {
  onSave: (newCase: CaseData) => void;
  onCancel: () => void;
  onDelete?: (id: string) => void;
  initialData?: CaseData | null;
}

const AddCaseForm: React.FC<AddCaseFormProps> = ({ onSave, onCancel, onDelete, initialData }) => {
  const [formData, setFormData] = useState<Partial<CaseData>>(
    initialData || {
      caseType: CaseType.GUGATAN,
      year: new Date().getFullYear().toString(),
      decisionDate: new Date().toISOString().split('T')[0],
      isArchived: false
    }
  );

  const [storage, setStorage] = useState<StorageLocation>(
    initialData?.storage || { roomNo: '', shelfNo: '', levelNo: '', boxNo: '' }
  );

  const [pdfUrl, setPdfUrl] = useState<string | undefined>(initialData?.pdfUrl);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      setIsUploading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPdfUrl(reader.result as string);
        setIsUploading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.caseNumber || !formData.classification || !formData.parties) return;

    // Build the case number if it's new
    let fullCaseNum = formData.caseNumber || '';
    if (!fullCaseNum.includes('/')) {
       fullCaseNum = `${formData.caseNumber}/${formData.caseType === CaseType.GUGATAN ? 'Pdt.G' : 'Pdt.P'}/${formData.year || new Date().getFullYear()}/PA.Pbm`;
    }

    const finalCase: CaseData = {
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      caseNumber: fullCaseNum,
      caseType: (formData.caseType as CaseType) || CaseType.GUGATAN,
      classification: formData.classification as string,
      parties: formData.parties as string,
      decisionDate: formData.decisionDate as string,
      bhtDate: formData.bhtDate,
      isArchived: !!formData.isArchived,
      storage: formData.isArchived ? storage : undefined,
      pdfUrl: pdfUrl
    };

    onSave(finalCase);
  };

  const handleDeleteSelf = () => {
    if (initialData && onDelete && window.confirm(`Hapus PERKARA nomor ${initialData.caseNumber} secara permanen? Seluruh data akan hilang.`)) {
      onDelete(initialData.id);
    }
  };

  const handleResetMinutasi = () => {
    if (initialData && window.confirm(`Hapus STATUS MINUTASI untuk perkara ${initialData.caseNumber}? Data lokasi arsip dan dokumen digital akan dibersihkan.`)) {
      const resetCase: CaseData = {
        ...initialData,
        isArchived: false,
        storage: undefined,
        pdfUrl: undefined
      };
      onSave(resetCase);
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-in fade-in zoom-in-95 duration-300">
      <div className={`p-1 bg-gradient-to-r ${initialData ? 'from-blue-600 to-indigo-600' : 'from-emerald-600 to-teal-600'}`}></div>
      <div className="p-8">
        <div className="flex justify-between items-center mb-8">
          <div className="flex items-center gap-3">
            <div className={`${initialData ? 'bg-blue-100 text-blue-600' : 'bg-emerald-100 text-emerald-600'} p-2 rounded-xl`}>
              {initialData ? <Archive className="w-6 h-6" /> : <FilePlus2 className="w-6 h-6" />}
            </div>
            <div>
              <h2 className="text-xl font-bold text-slate-800">
                {initialData ? 'Update & Minutasi Perkara' : 'Input Perkara Baru'}
              </h2>
              <p className="text-slate-500 text-sm">
                {initialData ? 'Lengkapi lokasi fisik dan dokumen digital.' : 'Tambahkan data perkara ke dalam sistem.'}
              </p>
            </div>
          </div>
          <button type="button" onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          {/* Section 1: Data Dasar */}
          <div className="space-y-4">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest border-b pb-2">Informasi Identitas</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Nomor Urut Perkara</label>
                  <input 
                    type="text" required placeholder="Contoh: 1234"
                    disabled={!!initialData}
                    defaultValue={initialData ? initialData.caseNumber.split('/')[0] : ''}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium disabled:opacity-50"
                    onChange={e => setFormData({...formData, caseNumber: e.target.value})}
                  />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Jenis</label>
                    <select 
                      disabled={!!initialData}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium appearance-none disabled:opacity-50"
                      value={formData.caseType}
                      onChange={e => setFormData({...formData, caseType: e.target.value as CaseType})}
                    >
                      <option value={CaseType.GUGATAN}>Gugatan</option>
                      <option value={CaseType.PERMOHONAN}>Permohonan</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Tahun</label>
                    <input 
                      type="number" disabled={!!initialData}
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium disabled:opacity-50"
                      value={formData.year}
                      onChange={e => setFormData({...formData, year: e.target.value})}
                    />
                  </div>
                </div>
              </div>
              <div className="space-y-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Klasifikasi</label>
                  <input 
                    type="text" required placeholder="Cerai Gugat"
                    value={formData.classification}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                    onChange={e => setFormData({...formData, classification: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Pihak / Pemohon</label>
                  <input 
                    type="text" required placeholder="Nama Pihak"
                    value={formData.parties}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
                    onChange={e => setFormData({...formData, parties: e.target.value})}
                  />
                </div>
              </div>
            </div>
          </div>

          {/* Section 2: Status Minutasi */}
          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-lg ${formData.isArchived ? 'bg-green-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                  <Archive className="w-5 h-5" />
                </div>
                <div>
                  <h3 className="font-bold text-slate-800">Status Minutasi</h3>
                  <p className="text-xs text-slate-500">Tentukan apakah berkas sudah masuk ke ruang arsip.</p>
                </div>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input 
                  type="checkbox" 
                  className="sr-only peer" 
                  checked={formData.isArchived}
                  onChange={e => setFormData({...formData, isArchived: e.target.checked})}
                />
                <div className="w-14 h-7 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-green-600"></div>
              </label>
            </div>

            {formData.isArchived && (
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in slide-in-from-top-2 duration-300">
                {/* Lokasi Fisik */}
                <div className="space-y-4">
                  <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
                    <MapPin className="w-3 h-3" /> Lokasi Fisik
                  </h4>
                  <div className="grid grid-cols-2 gap-3">
                    <StorageInput label="Ruang" value={storage.roomNo} onChange={v => setStorage({...storage, roomNo: v})} />
                    <StorageInput label="Lemari" value={storage.shelfNo} onChange={v => setStorage({...storage, shelfNo: v})} />
                    <StorageInput label="Tingkat" value={storage.levelNo} onChange={v => setStorage({...storage, levelNo: v})} />
                    <StorageInput label="Box" value={storage.boxNo} onChange={v => setStorage({...storage, boxNo: v})} />
                  </div>
                </div>

                {/* Berkas Digital */}
                <div className="space-y-4">
                  <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
                    <FileUp className="w-3 h-3" /> Dokumen Digital (PDF)
                  </h4>
                  <div className="flex flex-col gap-3">
                    <input type="file" ref={fileInputRef} className="hidden" accept="application/pdf" onChange={handleFileUpload} />
                    {pdfUrl ? (
                      <div className="flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl">
                        <div className="flex items-center gap-2 overflow-hidden">
                          <FileText className="w-5 h-5 text-blue-600 shrink-0" />
                          <span className="text-xs font-bold text-slate-600 truncate">Berkas_Digital.pdf</span>
                        </div>
                        <button type="button" onClick={() => setPdfUrl(undefined)} className="text-red-500 hover:bg-red-50 p-1.5 rounded-lg">
                          <X className="w-4 h-4" />
                        </button>
                      </div>
                    ) : (
                      <button 
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full py-6 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center gap-2 text-slate-400 hover:border-blue-400 hover:text-blue-500 transition-all bg-white"
                      >
                        {isUploading ? <Loader2 className="w-6 h-6 animate-spin" /> : <FileUp className="w-6 h-6" />}
                        <span className="text-xs font-bold">Pilih atau Scan PDF</span>
                      </button>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="flex flex-col sm:flex-row gap-4 pt-4 border-t border-slate-100">
            {initialData && (
              <div className="flex gap-2">
                 {initialData.isArchived && (
                   <button 
                    type="button" 
                    onClick={handleResetMinutasi}
                    className="flex items-center justify-center gap-2 px-6 py-4 border border-blue-200 text-blue-600 rounded-xl font-bold hover:bg-blue-50 transition-all shrink-0"
                    title="Hapus Status Minutasi Saja"
                  >
                    <RotateCcw className="w-5 h-5" />
                    Reset Minutasi
                  </button>
                 )}
                <button 
                  type="button" 
                  onClick={handleDeleteSelf}
                  className="flex items-center justify-center gap-2 px-6 py-4 border border-red-200 text-red-600 rounded-xl font-bold hover:bg-red-50 transition-all shrink-0"
                  title="Hapus Seluruh Data Perkara"
                >
                  <Trash2 className="w-5 h-5" />
                  Hapus Perkara
                </button>
              </div>
            )}
            <div className="flex-1 flex gap-4">
              <button type="button" onClick={onCancel} className="flex-1 py-4 border border-slate-200 text-slate-600 rounded-xl font-bold hover:bg-slate-50 transition-all">
                Batal
              </button>
              <button 
                type="submit" 
                className={`flex-[2] py-4 rounded-xl font-bold transition-all shadow-xl flex items-center justify-center gap-2 text-white ${
                  initialData ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-100'
                }`}
              >
                <Save className="w-5 h-5" />
                {initialData ? 'Simpan Perubahan' : 'Simpan Data Perkara'}
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

const StorageInput = ({ label, value, onChange }: { label: string, value: string, onChange: (v: string) => void }) => (
  <div>
    <label className="block text-[10px] text-slate-500 font-bold mb-1 ml-1">{label}</label>
    <input 
      type="text" value={value} onChange={e => onChange(e.target.value)}
      className="w-full px-3 py-2 bg-white border border-slate-200 rounded-lg text-xs font-bold focus:ring-2 focus:ring-blue-500 outline-none"
    />
  </div>
);

