    if (window.confirm(`HAPUS STATUS MINUTASI untuk perkara ${caseData.caseNumber}?\n\nData lokasi fisik dan dokumen digital akan dibersihkan. Berkas akan kembali ke status 'Proses'.`)) {
      onUpdateCase({
        ...caseData,
        isArchived: false,
