                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={activeTab === CaseType.GUGATAN ? 8 : 7} className="py-12 text-center text-slate-400 italic text-sm">
                      Data tidak ditemukan dalam database lokal.
                    </td>
                  </tr>
